import { useState, useEffect } from 'react'
import { supabase, GROUPS, getAge } from '../lib/supabase'
import PlayerModal from '../components/PlayerModal'

const TEAM_PHOTOS = {
  '+30': 'data:image/jpeg;base64,',
  '+40': 'data:image/jpeg;base64,',
  '+50': 'data:image/jpeg;base64,',
}

const ROLE_ORDER = { coach: 0, assistant_coach: 1, captain: 2, vice_captain: 3 }
const ROLE_LABEL = { coach: 'Coach', assistant_coach: 'Co-Coach', captain: 'Capitaine', vice_captain: 'Vice-Cap.' }
const ROLE_COLOR = { coach: '#c0161a', assistant_coach: '#8b0f12', captain: '#FFD700', vice_captain: '#e6c200' }
const ROLE_TEXT = { coach: 'white', assistant_coach: 'white', captain: '#5a4500', vice_captain: '#5a4500' }

export default function Joueurs({ currentPlayer, isAdmin }) {
  const [players, setPlayers] = useState([])
  const [tests, setTests] = useState([])
  const [activeGroup, setActiveGroup] = useState(currentPlayer?.group_name || '+30')
  const [search, setSearch] = useState('')
  const [selected, setSelected] = useState(null)
  const [loading, setLoading] = useState(true)

  const fetchData = async () => {
    const { data: pData } = await supabase.from('players').select('*').eq('active', true).order('last_name')
    const { data: tData } = await supabase.from('fitness_tests').select('*')
    setPlayers(pData || [])
    setTests(tData || [])
    setLoading(false)
  }

  useEffect(() => { fetchData() }, [])

  const initials = (p) => `${p.first_name?.[0] || ''}${p.last_name?.[0] || ''}`.toUpperCase()

  const sortPlayers = (list) => {
    return [...list].sort((a, b) => {
      if (a.team_role === 'coach') return -1
      if (b.team_role === 'coach') return 1
      if (a.team_role === 'assistant_coach') return -1
      if (b.team_role === 'assistant_coach') return 1
      // Ascending by birthdate: oldest first (smallest year = oldest)
      const da = a.born || '9999'
      const db = b.born || '9999'
      return da.localeCompare(db)
    })
  }

  const filtered = search.trim()
    ? players.filter(p =>
        `${p.first_name} ${p.last_name}`.toLowerCase().includes(search.toLowerCase()) ||
        (p.position || '').toLowerCase().includes(search.toLowerCase()) ||
        (p.job || '').toLowerCase().includes(search.toLowerCase()) ||
        (p.passions || '').toLowerCase().includes(search.toLowerCase()) ||
        p.group_name.includes(search)
      )
    : sortPlayers(players.filter(p => p.group_name === activeGroup))

  const groupLabel = { '+30': 'Seniors +30', '+40': 'Seniors +40', '+50': 'Seniors +50' }

  if (loading) return <div className="loading">Chargement...</div>

  return (
    <>
      <div className="search-wrap">
        <input className="search-input" type="text" placeholder="Rechercher nom, poste, passion, groupe..." value={search} onChange={e => setSearch(e.target.value)} />
      </div>

      <div className="content">
        {!search.trim() && (
          <>
            <div className="group-tabs">
              {GROUPS.map(g => (
                <div key={g} className={`group-tab${g === activeGroup ? ' active' : ''}`} onClick={() => setActiveGroup(g)}>{g}</div>
              ))}
            </div>
            <div className="hero-banner">
              <img src={TEAM_PHOTOS[activeGroup]} alt="Équipe" className="hero-img" />
              <div className="hero-overlay">
                <div className="hero-text">{groupLabel[activeGroup]}</div>
              </div>
            </div>
          </>
        )}

        {filtered.length === 0
          ? <div className="no-results">Aucun joueur trouvé</div>
          : <div className="player-grid">
              {filtered.map(p => (
                <div key={p.id} className={`player-card${!p.active ? ' player-inactive' : ''}`} onClick={() => setSelected(p)}>
                  <div className="player-card-top">
                    {p.born && <span className="player-age">{getAge(p.born)}</span>}
                  </div>
                  {p.photo_url
                    ? <img src={p.photo_url} className="player-photo" alt={p.last_name} />
                    : <div className="player-avatar">{initials(p)}</div>
                  }
                  <div className="player-name">
                    {p.first_name} {p.last_name}
                    {p.team_role === 'captain' && <span className="captain-tag" style={{background:'#FFD700',color:'#5a4500'}}>C</span>}
                    {p.team_role === 'vice_captain' && <span className="captain-tag" style={{background:'#aaa',color:'white'}}>C</span>}
                  </div>
                  <div className="player-pos">{p.preferred_position || p.position || '—'}</div>
                  {p.born && <div className="player-born">{p.born.split('-').reverse().join('.')}</div>}
                  {p.team_role && ['coach','assistant_coach'].includes(p.team_role) && (
                    <span className="role-badge" style={{background: ROLE_COLOR[p.team_role], color: ROLE_TEXT[p.team_role]}}>
                      {ROLE_LABEL[p.team_role]}
                    </span>
                  )}
                  <span className="player-group-tag">Seniors {p.group_name}</span>
                </div>
              ))}
            </div>
        }
      </div>

      {selected && (
        <PlayerModal
          player={selected}
          tests={tests.filter(t => t.player_id === selected.id)}
          isOwn={currentPlayer?.id === selected.id}
          isAdmin={isAdmin}
          onClose={() => setSelected(null)}
          onUpdate={() => { fetchData(); }}
        />
      )}
    </>
  )
}
